// Generated by OrchestKit Claude Plugin
// Created: 2026-06-07

// Documentation search over a prebuilt lightweight index
// (@/lib/generated/docs-search-index — {url,title,description} per page,
// generated by scripts/gen-docs-search-index.js). Deliberately does NOT import
// the compiled Fumadocs source: loading that at cold start pushed the NLWeb
// /ask serverless function to ~3.9s cold, which timed out agent-readiness
// scanners even though the endpoint is fully conformant when warm. Full page
// bodies live in @/lib/doc-markdown (source-backed), used only by the MCP
// full-content path.

import { SITE } from "@/lib/constants";
import { DOCS_SEARCH_INDEX } from "@/lib/generated/docs-search-index";

export type DocHit = {
	id: string;
	title: string;
	url: string;
	content: string;
};

export function searchDocs(query: string, max = 10): DocHit[] {
	const terms = query
		.toLowerCase()
		.split(/[^a-z0-9]+/)
		.filter((t) => t.length > 1);
	if (terms.length === 0) return [];

	const scored: Array<DocHit & { score: number }> = [];
	for (const page of DOCS_SEARCH_INDEX) {
		const title = page.title.toLowerCase();
		const desc = page.description.toLowerCase();
		let score = 0;
		for (const term of terms) {
			if (title.includes(term)) score += 3;
			if (desc.includes(term)) score += 1;
		}
		if (score > 0) {
			scored.push({
				id: page.url,
				title: page.title || page.url,
				url: `${SITE.domain}${page.url}`,
				content: page.description,
				score,
			});
		}
	}
	return scored
		.sort((a, b) => b.score - a.score)
		.slice(0, max)
		.map(({ score: _score, ...hit }) => hit);
}
